t.script:
document.addEventListener("DOMContentLoaded", function() {
    // 1. Sidebar tab switching and URL hash routing logic
    const menuItems = document.querySelectorAll(".menu-item");
    const tabContents = document.querySelectorAll(".tab-content");

    function switchTab(tabName) {
        menuItems.forEach(mi => {
            if (mi.getAttribute("data-tab") === tabName) {
                mi.classList.add("active");
            } else {
                mi.classList.remove("active");
            }
        });

        tabContents.forEach(tc => {
            if (tc.id === "tab-" + tabName) {
                tc.classList.add("active");
            } else {
                tc.classList.remove("active");
            }
        });
    }

    menuItems.forEach(item => {
        item.addEventListener("click", function() {
            const tabName = this.getAttribute("data-tab");
            window.location.hash = tabName;
        });
    });

    function handleHash() {
        const hash = window.location.hash.substring(1);
        if (hash) {
            switchTab(hash);
        }
    }
    window.addEventListener("hashchange", handleHash);
    handleHash(); // Switch tab if hash is present on load

    // 2. Modal helpers
    window.openModal = function(id) {
        const m = document.getElementById(id);
        if (m) m.classList.add("active");
    };
    window.closeModal = function(id) {
        const m = document.getElementById(id);
        if (m) m.classList.remove("active");
    };

    // 3. Complete trip modal helper
    window.openCompleteTripModal = function(tripId, tripName, currentOdo) {
        const modal = document.getElementById('completeTripModal');
        const form = document.getElementById('completeTripForm');
        const nameSpan = document.getElementById('modalTripName');
        const odoSpan = document.getElementById('modalCurrentOdo');
        const finalOdoInput = document.getElementById('modalFinalOdo');
        const errBox = document.getElementById('odoValidationError');
        const submitBtn = document.getElementById('completeSubmitBtn');

        if (modal && form) {
            form.action = '/transitops/trip/' + tripId + '/complete';
            nameSpan.textContent = tripName;
            odoSpan.textContent = currentOdo;
            finalOdoInput.value = currentOdo + 10;
            finalOdoInput.min = currentOdo;
            errBox.style.display = 'none';
            submitBtn.disabled = false;

            finalOdoInput.oninput = function() {
                const val = parseInt(finalOdoInput.value || '0');
                if (val < currentOdo) {
                    errBox.style.display = 'block';
                    submitBtn.disabled = true;
                } else {
                    errBox.style.display = 'none';
                    submitBtn.disabled = false;
                }
            };

            modal.classList.add('active');
        }
    };

    // 4. Cancel trip confirmation helper
    window.confirmCancelTrip = function(tripId, tripName) {
        if (confirm("Are you sure you want to cancel Trip " + tripName + "? This will release the vehicle and driver.")) {
            window.location.href = '/transitops/trip/' + tripId + '/cancel';
        }
    };

    // 5. Cargo capacity validation logic for dispatcher
    const vehicleSelect = document.getElementById("tripVehicleSelect");
    const cargoInput = document.getElementById("tripCargoWeight");
    const errorBox = document.getElementById("capacityErrorBox");
    const errorText = document.getElementById("capacityErrorText");
    const submitBtn = document.getElementById("tripSubmitBtn");

    function validateCapacity() {
        if (!vehicleSelect || !cargoInput) return;
        const selectedOption = vehicleSelect.options[vehicleSelect.selectedIndex];
        if (!selectedOption || !selectedOption.value) {
            errorBox.style.display = "none";
            submitBtn.disabled = false;
            submitBtn.style.opacity = "";
            submitBtn.style.cursor = "";
            return;
        }
        const capacity = parseInt(selectedOption.getAttribute("data-capacity") || "0");
        const weight = parseInt(cargoInput.value || "0");
        if (weight > capacity) {
            const diff = weight - capacity;
            errorText.textContent = "Vehicle Capacity: " + capacity + " kg, Cargo Weight: " + weight + " kg. Capacity exceeded by " + diff + " kg - dispatch blocked.";
            errorBox.style.display = "block";
            submitBtn.disabled = true;
            submitBtn.style.opacity = "0.5";
            submitBtn.style.cursor = "not-allowed";
        } else {
            errorBox.style.display = "none";
            submitBtn.disabled = false;
            submitBtn.style.opacity = "";
            submitBtn.style.cursor = "";
        }
    }
    if (vehicleSelect) {
        if (cargoInput) {
            vehicleSelect.addEventListener("change", validateCapacity);
            cargoInput.addEventListener("input", validateCapacity);
        }
    }

    // 6. Global search bar input filtering logic
    const searchInput = document.getElementById("portalSearch");
    if (searchInput) {
        searchInput.addEventListener("keyup", function() {
            const filterText = this.value.toLowerCase().trim();
            const activeTab = document.querySelector(".tab-content.active");
            if (!activeTab) return;

            const rows = activeTab.querySelectorAll("table tbody tr");
            rows.forEach(row => {
                const cells = row.querySelectorAll("td");
                let rowMatches = false;
                cells.forEach(cell => {
                    if (cell.textContent.toLowerCase().includes(filterText)) {
                        rowMatches = true;
                    }
                });
                if (rowMatches || filterText === "") {
                    row.style.display = "";
                } else {
                    row.style.display = "none";
                }
            });
        });
    }
});
